Advance -> {}
Reset -> {}

Iterator -> {
  T <- none
  i32:index >>- Advance -> 0
  List{T <- T}:items
  Advance -< e {
    index -<< index + 1
  }
  Reset -< e {
    index -<< 0
  }
  next -> {
    >- Advance{}
  }
  current -> {
    -> items.index
  }
  done -> {
    -> index >= items.length
  }
}
